// Extract THE documentation dimension: the autogenerated *.generated.test.ts cells
// (connector='documentation') produced by the doc-code extractor. A SEPARATE world
// from the hand-written matrix tests (extractTests.ts) — these are docs/**/*.md
// snippets, copied per database into the matrix and either type-checked or
// SQL-asserted. They have no life of their own; their destination is the markdown.
//
// EVERY snippet is indexed (one BEGIN/END region in the generated file), classified by
// kind — 'test' (ts paired with documented SQL, asserted), 'fn' (compile-only ts,
// type-checked), 'decl' (typescript type declarations at module level, e.g.
// simplifiedDefinition). Each is located by its SOURCE markdown (page + nearest heading
// + fence line range), with the generated .test.ts span kept as gen_* so the agent can
// read that exact snippet without the whole doc.
//
// Symbol positions (doc_test_ref) are taken from the COMPILED generated cell (it lives
// in the unified Program, so the checker resolves each reference) within the BEGIN/END
// region, then mapped back to .md coordinates: the in-region copy is verbatim
// line-for-line, so md_line = gen_line + (md_start - begin_file_line) and md_col is
// unchanged. No in-memory .md slice is parsed — the only thing read from the .md is the
// nearest heading for the block.

import ts from 'typescript'
import { readFileSync } from 'node:fs'
import { resolve } from 'node:path'
import { walkFiles } from './walk.js'
import { cellOf, asTestCall, describeName, firstStringArg, collectRefPositions } from './extractTests.js'
import { resolveToken } from './resolve.js'
import type { DeclMap } from './resolve.js'
import type { Ids, DocTestBlockRow, DocTestRefRow } from './model.js'

export interface DocTestExtract {
    docTestBlocks: DocTestBlockRow[]
    docTestRefs: DocTestRefRow[]
}

const MARKER_RE = /^\/\/ (BEGIN|END) (\S+):(\d+)$/
const HEADING_RE = /^#{1,6}\s+(.*)$/

function areaOf(page: string): string {
    // docs/<area>/<...>.md  → 'queries' | 'advanced' | … ('root' for docs/*.md)
    const parts = page.split('/')
    if (parts[0] !== 'docs') return 'root'
    const seg = parts[1]
    return seg && !seg.endsWith('.md') ? seg : 'root'
}

// Nearest markdown heading at or above a 1-based source line.
function headingAbove(mdLines: string[], line: number): string | null {
    for (let i = Math.min(line, mdLines.length) - 1; i >= 0; i--) {
        const m = HEADING_RE.exec(mdLines[i]!)
        if (m) return m[1]!.trim()
    }
    return null
}

interface TestSpan { start: number, end: number, name: string, active: boolean }
interface Span { start: number, end: number }
interface DeclAt { line: number, name: string }

// Pre-collect the test() and function spans so each BEGIN/END region can be
// classified by what encloses it: inside a test() → 'test'; inside an
// `async function …` → 'fn'; module top-level → 'decl'. Also collect the
// interface/class declarations + their lines, so a snippet that declares a
// SIMPLIFIED def (e.g. `interface SelectExpression { … }`) can be tagged with it.
function collectSpans(sf: ts.SourceFile): { tests: TestSpan[], fns: Span[], decls: DeclAt[] } {
    const tests: TestSpan[] = []
    const fns: Span[] = []
    const decls: DeclAt[] = []
    const stack: string[] = []
    const lineOf = (pos: number): number => sf.getLineAndCharacterOfPosition(pos).line + 1
    const visit = (node: ts.Node): void => {
        if (ts.isInterfaceDeclaration(node) || (ts.isClassDeclaration(node) && node.name)) {
            decls.push({ line: lineOf(node.getStart(sf)), name: node.name!.text })
        }
        if (ts.isCallExpression(node)) {
            const dn = describeName(node)
            if (dn !== null) {
                stack.push(dn)
                const cb = node.arguments.find(a => ts.isArrowFunction(a) || ts.isFunctionExpression(a))
                if (cb) ts.forEachChild(cb, visit)
                stack.pop()
                return
            }
            const tc = asTestCall(node)
            if (tc) {
                const tname = firstStringArg(node)
                if (tname !== null) tests.push({ start: lineOf(node.getStart(sf)), end: lineOf(node.getEnd()), name: [...stack, tname].join(' > '), active: tc.active })
                return
            }
        }
        if (ts.isFunctionDeclaration(node)) fns.push({ start: lineOf(node.getStart(sf)), end: lineOf(node.getEnd()) })
        ts.forEachChild(node, visit)
    }
    visit(sf)
    return { tests, fns, decls }
}

function processFile(
    relPath: string, ids: Ids, blocks: DocTestBlockRow[], refs: DocTestRefRow[],
    program: ts.Program, checker: ts.TypeChecker, declMap: DeclMap, mdCache: Map<string, string[]>,
): void {
    const cell = cellOf(relPath)
    if (!cell || cell.connector !== 'documentation') return
    // The COMPILED generated cell from the unified Program (resolvable, complete file).
    const sf = program.getSourceFile(resolve(relPath))
    if (!sf) return
    const fileLines = sf.text.split('\n')
    const { tests, fns, decls } = collectSpans(sf)

    const mdOf = (page: string): string[] => {
        let l = mdCache.get(page)
        if (!l) { l = readFileSync(page, 'utf8').split('\n'); mdCache.set(page, l) }
        return l
    }
    const containing = <T extends Span>(spans: T[], line: number): T | null => {
        for (const s of spans) if (s.start <= line && line <= s.end) return s
        return null
    }

    // All API references in the generated cell, ONCE, with gen-file coordinates + token
    // node (to checker-resolve). Each is bucketed into the BEGIN/END region it falls in.
    const allRefs = collectRefPositions(sf, sf)

    // Walk the BEGIN/END marker pairs (snippets don't nest).
    let i = 0
    while (i < fileLines.length) {
        const mb = MARKER_RE.exec(fileLines[i]!)
        if (!mb || mb[1] !== 'BEGIN') { i++; continue }
        const page = mb[2]!, mdStart = Number(mb[3])
        const beginFileLine = i + 1
        let endFileLine = -1, mdEnd = mdStart, j = i + 1
        for (; j < fileLines.length; j++) {
            const me = MARKER_RE.exec(fileLines[j]!)
            if (me && me[1] === 'END' && me[2] === page) { endFileLine = j + 1; mdEnd = Number(me[3]); break }
        }
        if (endFileLine < 0) { i++; continue }   // unmatched BEGIN (shouldn't happen)

        const t = containing(tests, beginFileLine)
        const kind: DocTestBlockRow['kind'] = t ? 'test' : (containing(fns, beginFileLine) ? 'fn' : 'decl')
        // The simplified def this snippet declares, if any: an interface/class decl INSIDE the region.
        const declared = decls.find(d => d.line > beginFileLine && d.line < endFileLine)
        const blockId = ids.next()
        blocks.push({
            id: blockId, page, area: areaOf(page), heading: headingAbove(mdOf(page), mdStart),
            db: cell.db, kind, simplified_def: declared ? declared.name : null,
            start_line: mdStart, end_line: mdEnd,
            name: t ? t.name : `${page}:${mdStart}`,
            gen_file: relPath, gen_start_line: beginFileLine, gen_end_line: endFileLine,
            is_active: t ? (t.active ? 1 : 0) : 1,
        })
        // In-region copy is verbatim line-for-line; map gen → .md coordinates.
        const offset = mdStart - beginFileLine
        for (const r of allRefs) {
            if (r.line <= beginFileLine || r.line >= endFileLine) continue
            const res = resolveToken(checker, declMap, r.node)
            refs.push({
                doc_test_block_id: blockId, symbol_name: r.name,
                md_line: r.line + offset, md_col: r.col,
                resolved_symbol_id: res?.symbol_id ?? null, resolved_member_id: res?.member_id ?? null,
            })
        }
        i = j + 1
    }
}

export function extractDocTests(program: ts.Program, checker: ts.TypeChecker, declMap: DeclMap, ids: Ids): DocTestExtract {
    // Only the documentation cells — cheap walk, a handful of generated files.
    const files = walkFiles('test/db', '.test.ts').filter(f => f.includes('/documentation/'))
    const docTestBlocks: DocTestBlockRow[] = []
    const docTestRefs: DocTestRefRow[] = []
    const mdCache = new Map<string, string[]>()
    for (const f of files.sort()) processFile(f, ids, docTestBlocks, docTestRefs, program, checker, declMap, mdCache)
    return { docTestBlocks, docTestRefs }
}
